#!/usr/bin/env bash
# Obfuscated bootstrap wrapper (temp-file exec variant)
# Generated by make-obfuscated-sh.sh
set -euo pipefail

# The generator sets OBF_ENCRYPTED accordingly; for encrypted payloads, provide OBF_PASS at runtime.
: "${OBF_ENCRYPTED:=0}"

# ---- Decoders ----
dec_b64()  { base64 -d; }
dec_gzip() { gzip -dc; }
dec_aes()  { openssl enc -aes-256-cbc -md sha256 -pbkdf2 -d -pass env:OBF_PASS; }

# Extract everything after the payload marker
extract_payload() {
  awk 'f{print} /^__PAYLOAD__$/ {f=1}' "$0"
}

# Run payload from a temp file (NOT via "bash -s")
run_payload() {
  tmp="$(mktemp)"; trap 'rm -f "$tmp"' EXIT
  if [ "${OBF_ENCRYPTED}" = "1" ]; then
    extract_payload | dec_b64 | dec_aes | dec_gzip > "$tmp"
  else
    extract_payload | dec_b64 | dec_gzip > "$tmp"
  fi
  exec /usr/bin/env bash "$tmp" "$@"
}

# Entry
OBF_ENCRYPTED=0

run_payload "$@"
exit 0

